import 'package:flutter/material.dart';import 'package:flutter_riverpod/flutter_riverpod.dart';import '../../../config/design_tokens.dart';import '../data/demo_search_data.dart';import 'search_controller.dart';
class SearchSheet extends ConsumerWidget{final VoidCallback onSubmit;const SearchSheet({super.key,required this.onSubmit});@override Widget build(BuildContext c,WidgetRef ref){final q=ref.watch(searchProvider);return Container(padding:EdgeInsets.fromLTRB(20,MediaQuery.paddingOf(c).top+12,20,20),decoration:const BoxDecoration(color:T.porcelain),child:ListView(children:[Row(children:[const Expanded(child:Text('Ankunft vorbereiten',style:TextStyle(fontSize:28,fontWeight:FontWeight.w900))),IconButton(onPressed:()=>Navigator.maybePop(c),icon:const Icon(Icons.close))]),const Text('Demo: Manuelle Suche funktioniert ohne Standortfreigabe.'),const SizedBox(height:18),const Text('Ziel',style:TextStyle(fontWeight:FontWeight.w800)),TextField(decoration:InputDecoration(hintText:'Messe, Bahnhof, Römerberg …',filled:true,fillColor:Colors.white,border:OutlineInputBorder(borderRadius:BorderRadius.circular(18))),onChanged:(v){final m=demoDestinations.where((d)=>d.name.toLowerCase().contains(v.toLowerCase())).firstOrNull;if(m!=null)ref.read(searchProvider.notifier).destination(m);}),Wrap(spacing:8,children:[ActionChip(avatar:const Icon(Icons.my_location),label:const Text('Demo-Standort Frankfurt'),onPressed:()=>ref.read(searchProvider.notifier).destination(demoDestinations[6])),...demoDestinations.map((d)=>ChoiceChip(label:Text(d.name),selected:q.destination?.id==d.id,onSelected:(_)=>ref.read(searchProvider.notifier).destination(d)))]),const SizedBox(height:18),const Text('Zeit',style:TextStyle(fontWeight:FontWeight.w800)),Wrap(spacing:8,children:[1,2,4].map((h)=>ChoiceChip(label:Text('$h Std.'),selected:q.hours==h,onSelected:(_)=>ref.read(searchProvider.notifier).duration(h))).toList()..add(ChoiceChip(label:const Text('Bis morgen'),selected:q.hours>8,onSelected:(_)=>ref.read(searchProvider.notifier).duration(16)) ) ),const SizedBox(height:18),const Text('Fahrzeug',style:TextStyle(fontWeight:FontWeight.w800)),...demoVehicles.map((v)=>RadioListTile(value:v.id,groupValue:q.vehicle?.id,title:Text(v.name),subtitle:Text('${v.plate} · H ${v.height}m · B ${v.width}m · L ${v.length}m'),onChanged:(_)=>ref.read(searchProvider.notifier).vehicle(v))),const SizedBox(height:16),FilledButton(onPressed:q.valid?onSubmit:null,child:const Text('Stellplätze anzeigen'))]));}}
